  id    String @id @default(uuid())
  name  String
  menu  MenuItem[]
  orders Order[]
}

model MenuItem {
  id           String     @id @default(uuid())
  name         String
  price        Float
  restaurantId String
  restaurant   Restaurant @relation(fields: [restaurantId], references: [id])
}

model Order {
  id           String      @id @default(uuid())
  restaurantId String
  restaurant   Restaurant  @relation(fields: [restaurantId], references: [id])
  items        OrderItem[]
}

model OrderItem {
  id       String   @id @default(uuid())
  orderId  String
  order    Order    @relation(fields: [orderId], references: [id])
  menuItemId String
}
"}

